# Category: serverless_security

import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub
from google.oauth2.service_account import Credentials

# Set the service account credentials
credentials = Credentials.from_service_account_file(os.environ['GOOGLE_APPLICATION_CREDENTIALS'])

# Create a client for Cloud Storage and Firestore
storage_client = storage.Client()
firestore_client = firestore.Client()
pubsub_client = pubsub.PubSubClient()

# Set the permissions for the service account
storage_admin = os.environ['GOOGLE_STORAGE_ADMIN']
datastore_user = os.environ['GOOGLE_DATASTORE_USER']
pubsub_publisher = os.environ['GOOGLE_PUBSUB_PUBLISHER']

# Define the function that will process files from Cloud Storage, write to Firestore, and publish to Pub/Sub
def process_files(bucket_name):
    # Get all the objects in the bucket
    bucket = storage_client.get_bucket(bucket_name)
    blobs = list(bucket.list_blobs())
    
    for blob in blobs:
        file_name = blob.name
        
        # Read the file contents and write to Firestore
        with open(file_name, 'rb') as f:
            data = f.read()
        doc_ref = firestore_client.document(f'{bucket_name}/{file_name}')
        doc_ref.set(data)
        
        # Publish the file contents to Pub/Sub
        topic_path = f'projects/{os.environ['GOOGLE_CLOUD_PROJECT']}/topics/{blob.topic}'
        publisher = pubsub_client.topic(topic_path)
        publisher.publish(data)